function makeRng(baseSeed, entityId, tag, tsMs) {
    const key = String(baseSeed) + ':' + String(entityId) + ':' + String(tag) + ':' + String(tsMs);
    const seedHex = crypto.createHash('sha256').update(key).digest('hex').slice(0, 16);
    return seedrandom.alea(seedHex);
}
function uniform(rng, a, b) { return a + (b - a) * rng(); }
function isWeekend(d) { const w = d.getUTCDay(); return w === 0 || w === 6; }
function dayOfYear(d) {
    const start = Date.UTC(d.getUTCFullYear(), 0, 0);
    return Math.floor((d.getTime() - start) / 86400000);
}
function calcSunTimes(date, latitude, longitude) {
    const doy = dayOfYear(date);
    const decl = 23.45 * Math.sin((Math.PI / 180) * (360 / 365) * (doy - 81));
    const declRad = decl * Math.PI / 180;
    const latRad = latitude * Math.PI / 180;
    let cosHa = -Math.tan(latRad) * Math.tan(declRad);
    cosHa = Math.max(-1, Math.min(1, cosHa));
    const haDeg = Math.acos(cosHa) * 180 / Math.PI;
    const noonH = 12 - longitude / 15;
    let sunriseH = Math.max(0, Math.min(23.99, noonH - haDeg / 15));
    let sunsetH = Math.max(0, Math.min(23.99, noonH + haDeg / 15));
    function fmt(h) {
        const hh = Math.floor(h);
        const mm = Math.floor((h - hh) * 60);
        return String(hh).padStart(2, '0') + ':' + String(mm).padStart(2, '0');
    }
    return [fmt(sunriseH), fmt(sunsetH), sunriseH, sunsetH];
}

const DEFAULT_CFG = {
    latitude: 52.52,
    longitude: 13.405
};

function fogFromTime(hour) {
    if (hour >= 4 && hour < 8) {
        const pf = 1 - Math.abs(hour - 6) / 2;
        return 50 * Math.max(0, pf);
    }
    if (hour >= 8 && hour < 14) return Math.max(0, 25 * (1 - (hour - 8) / 6));
    if (hour >= 20 && hour < 24) return 15 * ((hour - 20) / 4);
    if (hour >= 0 && hour < 4) return 20;
    return 5;
}

function classifyVisibility(fog) {
    if (fog < 30) return 'GOOD';
    if (fog < 60) return 'MEDIUM';
    return 'POOR';
}

function generateVisibility(payload) {
    const baseSeed = (typeof payload.base_seed === 'number') ? payload.base_seed : 12345;
    const entityId = payload.entity_id || 'visibility-default';
    const tsMs = (typeof payload.timestamp_ms === 'number') ? payload.timestamp_ms : 0;
    const isoTs = payload.timestamp || new Date(tsMs).toISOString();
    const cityId = payload.city_id || 'city-berlin';
    const cfg = Object.assign({}, DEFAULT_CFG, payload.config || {});
    const date = new Date(isoTs);
    const rng = makeRng(baseSeed, entityId, 'visibility', tsMs);
    const hour = date.getUTCHours() + date.getUTCMinutes() / 60;
    let fog = fogFromTime(hour);
    fog = Math.max(0, Math.min(100, fog + uniform(rng, -10, 10)));
    const [sunrise, sunset] = calcSunTimes(date, cfg.latitude, cfg.longitude);
    return {
        city_id: cityId, timestamp: isoTs,
        fog_index: fog,
        visibility: classifyVisibility(fog),
        sunrise_time: sunrise, sunset_time: sunset
    };
}

msg.payload = generateVisibility(msg.payload || {});
return msg;
